const config = $node["Set Configuration"].json;
const contract = $json;
const flags = [];

// 1. Bid Splitting check
const amt = Number(contract.Amount || 0);
const threshold = Number(config.tender_threshold || 100000);
if (amt >= threshold * 0.9 && amt < threshold) {
  flags.push("POTENTIAL_BID_SPLITTING (Value is " + amt + ", just below public tender threshold of " + threshold + ")");
}

// 2. Unusually fast turnaround check
const awardStr = contract.AwardDate || contract["Award Date"];
const pubStr = contract.PublishedDate || contract["Published Date"];
let diffDays = 999;
if (awardStr && pubStr) {
  const award = new Date(awardStr);
  const pub = new Date(pubStr);
  diffDays = Math.ceil(Math.abs(award - pub) / (1000 * 60 * 60 * 24));
  if (diffDays <= 3) {
    flags.push("SUSPICIOUS_SPEED (Awarded within " + diffDays + " days of publication)");
  }
}

// 3. Single Bidder check
const bidders = Number(contract.BiddersCount || contract["Bidders Count"] || 0);
if (bidders === 1 && contract.Method !== 'Direct Award') {
  flags.push("SINGLE_BIDDER_ANOMALY (Only 1 bidder in competitive category)");
}

return {
  ...contract,
  rule_flags: flags,
  rule_risk_points: flags.length * 20
};

const searchResult = $node["OpenCorporates Company Lookup"].json;
const contractData = $node["Evaluate Rules Engine"].json;
const awardDateStr = contractData.AwardDate || contractData["Award Date"];
const awardDate = awardDateStr ? new Date(awardDateStr) : new Date();

let companyAgeDays = 9999;
let isDissolved = false;
let jurisdiction = 'Unknown';
let companyAddress = 'Not Found';
let opencorporatesLink = '';
const flags = [];

try {
  if (searchResult && searchResult.results && searchResult.results.companies && searchResult.results.companies.length > 0) {
    const company = searchResult.results.companies[0].company;
    jurisdiction = company.jurisdiction_code || 'Unknown';
    companyAddress = company.registered_address_in_full || 'No address registered';
    opencorporatesLink = company.opencorporates_url || '';

    if (company.incorporation_date) {
      const incDate = new Date(company.incorporation_date);
      const diffTime = Math.abs(awardDate - incDate);
      companyAgeDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      if (companyAgeDays < 90) {
        flags.push("NEWLY_INCORPORATED_SUPPLIER (Incorporated " + companyAgeDays + " days before contract award)");
      }
    }

    const currentStatus = (company.current_status || '').toLowerCase();
    if (currentStatus.includes('dissolved') || currentStatus.includes('inactive') || currentStatus.includes('struck off')) {
      isDissolved = true;
      flags.push("INACTIVE_SUPPLIER (Company current status: " + company.current_status + ")");
    }
  } else {
    flags.push("UNREGISTERED_SUPPLIER (No company match found in registry search)");
  }
} catch (e) {
  // Catch errors and proceed with fallbacks
}

return {
  ...contractData,
  opencorporates_link: opencorporatesLink,
  company_jurisdiction: jurisdiction,
  company_address: companyAddress,
  company_age_days: companyAgeDays,
  company_status_inactive: isDissolved,
  registry_flags: flags,
  registry_risk_points: flags.length * 20
};

