let audit = { conflict_analysis: '', red_flags_summary: '', llm_risk_score: 0, investigation_notes: '' };
const profileData = $node["Evaluate Supplier Profile"].json;

try {
  const rawText = $node["Forensic Audit (LLM)"].json.choices[0].message.content;
  audit = JSON.parse(rawText);
} catch (e) {
  audit.conflict_analysis = "Could not analyze conflicts.";
  audit.red_flags_summary = "Review required.";
  audit.llm_risk_score = 10;
  audit.investigation_notes = "OpenAI parsing failed.";
}

const rulesScore = Number(profileData.rule_risk_points || 0);
const regScore = Number(profileData.registry_risk_points || 0);
const llmScore = Number(audit.llm_risk_score || 0);
let totalRisk = rulesScore + regScore + llmScore;
if (totalRisk > 100) totalRisk = 100;

let level = 'LOW';
if (totalRisk >= 75) {
  level = 'HIGH';
} else if (totalRisk >= 40) {
  level = 'MEDIUM';
}

// Combine all flags
const allFlags = [].concat(profileData.rule_flags || [], profileData.registry_flags || []);

return {
  ...profileData,
  final_risk_score: totalRisk,
  risk_level: level,
  all_risk_flags: allFlags.join('; '),
  conflict_analysis: audit.conflict_analysis,
  red_flags_summary: audit.red_flags_summary,
  investigation_notes: audit.investigation_notes
};

